//! Orchestrator — Central spawn point for all actors
//!
//! The Orchestrator holds typed channels to each actor and routes
//! messages accordingly. ToolActors are spawned dynamically on
//! ToolStart events.

use crate::event_bus::{
    ActorChannel, ActorId, BusEventEnvelope, DomainEvent, EphemeralEvent, EventBus,
};
use std::collections::HashMap;
use std::sync::Arc;
use std::thread::{self, JoinHandle};

/// Actor handle for sending messages to spawned actors
#[derive(Clone)]
pub struct ActorHandle {
    pub id: ActorId,
    tx: Arc<std::sync::mpsc::Sender<BusEventEnvelope>>,
}

impl ActorHandle {
    /// Send a domain event to this actor
    pub fn tell(&self, event: DomainEvent) {
        let _ = self.tx.send(BusEventEnvelope::Domain(event));
    }

    /// Send an ephemeral event to this actor
    pub fn tell_ephemeral(&self, event: EphemeralEvent) {
        let _ = self.tx.send(BusEventEnvelope::Ephemeral(event));
    }
}

/// Orchestrator manages all actors and their channels
pub struct Orchestrator {
    /// The shared event bus (thread-safe via Arc)
    bus: EventBus,
    /// Typed handles to all spawned actors
    actors: HashMap<ActorId, ActorHandle>,
    /// Join handles for actor threads
    threads: Vec<JoinHandle<()>>,
}

impl Default for Orchestrator {
    fn default() -> Self {
        Self::new()
    }
}

impl Orchestrator {
    /// Create a new orchestrator with the shared event bus
    pub fn new() -> Self {
        Self {
            bus: EventBus::new(),
            actors: HashMap::new(),
            threads: Vec::new(),
        }
    }

    /// Register an actor and return its channel
    pub fn register<T: Clone + Send + 'static>(&mut self, actor: ActorId) -> ActorChannel<T> {
        self.bus.register(actor)
    }

    /// Spawn an actor with its event handler
    ///
    /// The actor function receives the bus and its typed channel,
    /// and runs in a dedicated thread.
    pub fn spawn<F>(&mut self, id: ActorId, handler: F) -> ActorHandle
    where
        F: FnOnce(EventBus, ActorChannel<BusEventEnvelope>) + Send + 'static,
    {
        let channel = self.register::<BusEventEnvelope>(id.clone());
        let bus = self.bus.clone();

        let handle = ActorHandle {
            id: id.clone(),
            tx: Arc::new(channel.tx.clone()),
        };

        let thread = thread::spawn(move || {
            handler(bus, channel);
        });

        self.threads.push(thread);
        self.actors.insert(id, handle.clone());
        handle
    }

    /// Spawn the AgentLoop actor
    pub fn spawn_agent_loop<F>(&mut self, handler: F) -> ActorHandle
    where
        F: FnOnce(EventBus, ActorChannel<BusEventEnvelope>) + Send + 'static,
    {
        self.spawn(ActorId::AgentLoop, handler)
    }

    /// Spawn the QueueAgent actor
    pub fn spawn_queue_agent<F>(&mut self, handler: F) -> ActorHandle
    where
        F: FnOnce(EventBus, ActorChannel<BusEventEnvelope>) + Send + 'static,
    {
        self.spawn(ActorId::QueueAgent, handler)
    }

    /// Spawn the SessionManager actor
    pub fn spawn_session_manager<F>(&mut self, handler: F) -> ActorHandle
    where
        F: FnOnce(EventBus, ActorChannel<BusEventEnvelope>) + Send + 'static,
    {
        self.spawn(ActorId::SessionManager, handler)
    }

    /// Spawn the ConfigAgent actor
    pub fn spawn_config_agent<F>(&mut self, handler: F) -> ActorHandle
    where
        F: FnOnce(EventBus, ActorChannel<BusEventEnvelope>) + Send + 'static,
    {
        self.spawn(ActorId::ConfigAgent, handler)
    }

    /// Spawn a ToolActor dynamically on ToolStart events
    pub fn spawn_tool_actor<F>(&mut self, name: String, handler: F) -> ActorHandle
    where
        F: FnOnce(EventBus, ActorChannel<BusEventEnvelope>) + Send + 'static,
    {
        let id = ActorId::ToolActor { name };
        self.spawn(id, handler)
    }

    /// Get a handle to a spawned actor
    pub fn actor(&self, id: &ActorId) -> Option<&ActorHandle> {
        self.actors.get(id)
    }

    /// Get a clone of the shared event bus
    pub fn bus(&self) -> EventBus {
        self.bus.clone()
    }

    /// Send a domain event to a specific actor
    pub fn tell(&self, actor: &ActorId, event: DomainEvent) {
        if let Some(handle) = self.actors.get(actor) {
            handle.tell(event);
        }
    }

    /// Send an ephemeral event to a specific actor
    pub fn tell_ephemeral(&self, actor: &ActorId, event: EphemeralEvent) {
        if let Some(handle) = self.actors.get(actor) {
            handle.tell_ephemeral(event);
        }
    }

    /// Broadcast a domain event to all actors via the bus
    pub fn broadcast(&self, event: DomainEvent) {
        self.bus.publish_domain(event);
    }

    /// Broadcast an ephemeral event to all actors via the bus
    pub fn broadcast_ephemeral(&self, event: EphemeralEvent) {
        self.bus.publish_ephemeral(event);
    }

    /// Get list of all spawned actor IDs
    pub fn actor_ids(&self) -> Vec<ActorId> {
        self.actors.keys().cloned().collect()
    }

    /// Wait for all actor threads to complete
    pub fn shutdown(self) {
        // Drop the actors HashMap to release handles
        drop(self.actors);
        // Join all threads
        for thread in self.threads {
            let _ = thread.join();
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_orchestrator_creation() {
        let orch = Orchestrator::new();
        assert!(orch.actor_ids().is_empty());
    }

    #[test]
    fn test_spawn_actor() {
        let mut orch = Orchestrator::new();
        let received = Arc::new(std::sync::atomic::AtomicBool::new(false));
        let received_clone = received.clone();

        let handle = orch.spawn(ActorId::AgentLoop, move |_bus, _channel| {
            received_clone.store(true, std::sync::atomic::Ordering::SeqCst);
        });

        assert_eq!(handle.id, ActorId::AgentLoop);
        assert!(orch.actor(&ActorId::AgentLoop).is_some());
    }

    #[test]
    fn test_spawn_agent_loop() {
        let mut orch = Orchestrator::new();
        let handle = orch.spawn_agent_loop(|_bus, _channel| {});
        assert_eq!(handle.id, ActorId::AgentLoop);
    }

    #[test]
    fn test_spawn_queue_agent() {
        let mut orch = Orchestrator::new();
        let handle = orch.spawn_queue_agent(|_bus, _channel| {});
        assert_eq!(handle.id, ActorId::QueueAgent);
    }

    #[test]
    fn test_spawn_session_manager() {
        let mut orch = Orchestrator::new();
        let handle = orch.spawn_session_manager(|_bus, _channel| {});
        assert_eq!(handle.id, ActorId::SessionManager);
    }

    #[test]
    fn test_spawn_config_agent() {
        let mut orch = Orchestrator::new();
        let handle = orch.spawn_config_agent(|_bus, _channel| {});
        assert_eq!(handle.id, ActorId::ConfigAgent);
    }

    #[test]
    fn test_spawn_tool_actor() {
        let mut orch = Orchestrator::new();
        let handle = orch.spawn_tool_actor("bash".to_string(), |_bus, _channel| {});
        assert!(matches!(
            handle.id,
            ActorId::ToolActor { name } if name == "bash"
        ));
    }

    #[test]
    fn test_actor_handle_tell() {
        let (tx, rx) = std::sync::mpsc::channel();
        let handle = ActorHandle {
            id: ActorId::AgentLoop,
            tx: Arc::new(tx),
        };

        handle.tell(DomainEvent::Submit { content: "test".into() });

        let received = rx.recv_timeout(std::time::Duration::from_millis(100)).unwrap();
        match received {
            BusEventEnvelope::Domain(DomainEvent::Submit { content }) => {
                assert_eq!(content, "test");
            }
            _ => panic!("Expected domain Submit event"),
        }
    }

    #[test]
    fn test_actor_handle_tell_ephemeral() {
        let (tx, rx) = std::sync::mpsc::channel();
        let handle = ActorHandle {
            id: ActorId::InputActor,
            tx: Arc::new(tx),
        };

        handle.tell_ephemeral(EphemeralEvent::ScrollUp);

        let received = rx.recv_timeout(std::time::Duration::from_millis(100)).unwrap();
        match received {
            BusEventEnvelope::Ephemeral(EphemeralEvent::ScrollUp) => {}
            _ => panic!("Expected ephemeral ScrollUp event"),
        }
    }

    #[test]
    fn test_orchestrator_tell() {
        let mut orch = Orchestrator::new();
        let received = Arc::new(std::sync::atomic::AtomicBool::new(false));
        let received_clone = received.clone();

        let _handle = orch.spawn(ActorId::AgentLoop, move |_bus, channel: ActorChannel<BusEventEnvelope>| {
            while channel.rx.recv().is_ok() {
                received_clone.store(true, std::sync::atomic::Ordering::SeqCst);
                break;
            }
        });

        orch.tell(&ActorId::AgentLoop, DomainEvent::Submit { content: "test".into() });

        // Give thread time to receive
        std::thread::sleep(std::time::Duration::from_millis(10));
        assert!(received.load(std::sync::atomic::Ordering::SeqCst));
    }

    #[test]
    fn test_orchestrator_broadcast() {
        let mut orch = Orchestrator::new();
        let received = Arc::new(std::sync::atomic::AtomicBool::new(false));
        let received_clone = received.clone();

        let _handle = orch.spawn(ActorId::AgentLoop, move |bus, _channel| {
            bus.subscribe(ActorId::AgentLoop, crate::event_bus::SubscriptionFilter::domain_only());
            if bus.broadcast_try_recv().is_ok() {
                received_clone.store(true, std::sync::atomic::Ordering::SeqCst);
            }
        });

        orch.broadcast(DomainEvent::SpawnAgent);
    }

    #[test]
    fn test_orchestrator_actor_ids() {
        let mut orch = Orchestrator::new();
        assert!(orch.actor_ids().is_empty());

        let _h1 = orch.spawn_agent_loop(|_bus, _ch| {});
        let _h2 = orch.spawn_queue_agent(|_bus, _ch| {});

        let ids = orch.actor_ids();
        assert_eq!(ids.len(), 2);
        assert!(ids.contains(&ActorId::AgentLoop));
        assert!(ids.contains(&ActorId::QueueAgent));
    }

    #[test]
    fn test_multiple_tool_actors() {
        let mut orch = Orchestrator::new();
        let h1 = orch.spawn_tool_actor("bash".to_string(), |_bus, _ch| {});
        let h2 = orch.spawn_tool_actor("read".to_string(), |_bus, _ch| {});

        assert!(matches!(h1.id, ActorId::ToolActor { name } if name == "bash"));
        assert!(matches!(h2.id, ActorId::ToolActor { name } if name == "read"));
    }
}

//! Shared Event Bus with typed channels per actor
//!
//! Architecture:
//!   - Each actor has its own typed channel
//!   - Events are tagged as domain (persisted) or ephemeral (not persisted)
//!   - Subscribers can filter by event type and tag

use std::collections::HashMap;
use std::sync::mpsc::{channel, Receiver, Sender};
use std::sync::{Arc, Mutex};
use serde::{Deserialize, Serialize};

/// Event tag determines persistence behavior
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum EventTag {
    /// Domain events are persisted to session history
    Domain,
    /// Ephemeral events are not persisted
    Ephemeral,
}

/// Trait for event types that can be published on the bus
pub trait BusEvent: Clone + Send + 'static {
    /// Returns the event's tag (domain vs ephemeral)
    fn tag(&self) -> EventTag;
}

/// Domain events — persisted to session
#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum DomainEvent {
    Submit { content: String },
    SpawnAgent,
    AgentThinking { id: String },
    AgentThoughtDone { id: String },
    AgentResponse { id: String, content: String },
    AgentTurnComplete { id: String, duration_secs: f64 },
    AgentToolStart { id: String, name: String },
    AgentToolEnd { id: String, name: String, duration_secs: f64, output: String },
    AgentDone { id: String },
    AgentError { id: String, message: String },
    SwitchModel { provider: String, model: String },
    FollowUp { content: String },
    ToolRegistered { name: String },
    /// Bash command output (from ! prefix) — not sent to agent
    BashOutput { command: String, output: String },
}

impl BusEvent for DomainEvent {
    fn tag(&self) -> EventTag {
        EventTag::Domain
    }
}

/// Ephemeral events — not persisted
#[derive(Debug, Clone)]
pub enum EphemeralEvent {
    Input(char),
    Backspace,
    CursorLeft,
    CursorRight,
    CursorStart,
    CursorEnd,
    DeleteWord,
    DeleteToEnd,
    DeleteToStart,
    KillChar,
    HistoryPrev,
    HistoryNext,
    Undo,
    Redo,
    CursorWordLeft,
    CursorWordRight,
    Paste(String),
    ScrollUp,
    ScrollDown,
    ToggleExpand,
    Abort,
}

impl BusEvent for EphemeralEvent {
    fn tag(&self) -> EventTag {
        EventTag::Ephemeral
    }
}

/// Unified event envelope for the bus
#[derive(Debug, Clone)]
pub enum BusEventEnvelope {
    Domain(DomainEvent),
    Ephemeral(EphemeralEvent),
}

impl BusEventEnvelope {
    pub fn tag(&self) -> EventTag {
        match self {
            BusEventEnvelope::Domain(_) => EventTag::Domain,
            BusEventEnvelope::Ephemeral(_) => EventTag::Ephemeral,
        }
    }
}

/// Actor identifier for typed channels
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum ActorId {
    AgentLoop,
    QueueAgent,
    SessionManager,
    ConfigAgent,
    ToolActor { name: String },
    RenderActor,
    InputActor,
}

impl std::fmt::Display for ActorId {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            ActorId::AgentLoop => write!(f, "AgentLoop"),
            ActorId::QueueAgent => write!(f, "QueueAgent"),
            ActorId::SessionManager => write!(f, "SessionManager"),
            ActorId::ConfigAgent => write!(f, "ConfigAgent"),
            ActorId::ToolActor { name } => write!(f, "ToolActor({})", name),
            ActorId::RenderActor => write!(f, "RenderActor"),
            ActorId::InputActor => write!(f, "InputActor"),
        }
    }
}

/// Typed channel endpoint for an actor
#[derive(Debug)]
pub struct ActorChannel<T> {
    pub tx: Sender<T>,
    pub rx: Receiver<T>,
}

impl<T: Clone + Send + 'static> ActorChannel<T> {
    /// Create a new typed channel pair
    pub fn new() -> Self {
        let (tx, rx) = channel();
        Self { tx, rx }
    }

    /// Try to receive a message without blocking
    pub fn try_recv(&self) -> Result<T, std::sync::mpsc::TryRecvError> {
        self.rx.try_recv()
    }

    /// Receive a message, blocking until available
    pub fn recv(&self) -> Result<T, std::sync::mpsc::RecvError> {
        self.rx.recv()
    }
}

impl<T: Clone + Send + 'static> Default for ActorChannel<T> {
    fn default() -> Self {
        Self::new()
    }
}

/// Subscription filter for event filtering
#[derive(Debug, Clone, Default)]
pub struct SubscriptionFilter {
    pub include_domain: bool,
    pub include_ephemeral: bool,
}

impl SubscriptionFilter {
    pub fn all() -> Self {
        Self {
            include_domain: true,
            include_ephemeral: true,
        }
    }

    pub fn domain_only() -> Self {
        Self {
            include_domain: true,
            include_ephemeral: false,
        }
    }

    pub fn ephemeral_only() -> Self {
        Self {
            include_domain: false,
            include_ephemeral: true,
        }
    }

    pub fn matches(&self, event: &BusEventEnvelope) -> bool {
        match event {
            BusEventEnvelope::Domain(_) if !self.include_domain => false,
            BusEventEnvelope::Ephemeral(_) if !self.include_ephemeral => false,
            _ => true,
        }
    }
}

/// Thread-safe broadcast channel for inter-actor communication
#[derive(Clone)]
pub struct BroadcastChannel {
    tx: Sender<BusEventEnvelope>,
    rx: Arc<Mutex<Receiver<BusEventEnvelope>>>,
}

impl Default for BroadcastChannel {
    fn default() -> Self {
        Self::new()
    }
}

impl BroadcastChannel {
    /// Create a new broadcast channel
    pub fn new() -> Self {
        let (tx, rx) = channel();
        Self {
            tx,
            rx: Arc::new(Mutex::new(rx)),
        }
    }

    /// Send an event to all subscribers
    pub fn send(&self, event: BusEventEnvelope) -> Result<(), std::sync::mpsc::SendError<BusEventEnvelope>> {
        self.tx.send(event)
    }

    /// Try to receive without blocking
    pub fn try_recv(&self) -> Result<BusEventEnvelope, std::sync::mpsc::TryRecvError> {
        self.rx.lock().unwrap().try_recv()
    }

    /// Receive, blocking until available
    pub fn recv(&self) -> Result<BusEventEnvelope, std::sync::mpsc::RecvError> {
        self.rx.lock().unwrap().recv()
    }

    /// Get a cloned receiver for subscribing
    pub fn receiver(&self) -> Arc<Mutex<Receiver<BusEventEnvelope>>> {
        self.rx.clone()
    }
}

/// Shared event bus for inter-actor communication
#[derive(Clone, Default)]
pub struct EventBus {
    /// Broadcast channel for events
    broadcast: BroadcastChannel,
    /// Subscription filters per actor
    subscriptions: Arc<Mutex<HashMap<ActorId, SubscriptionFilter>>>,
}

impl EventBus {
    /// Create a new event bus
    pub fn new() -> Self {
        Self::default()
    }

    /// Subscribe an actor to specific event types
    pub fn subscribe(&self, actor: ActorId, filter: SubscriptionFilter) {
        self.subscriptions.lock().unwrap().insert(actor, filter);
    }

    /// Unsubscribe an actor
    pub fn unsubscribe(&self, actor: &ActorId) {
        self.subscriptions.lock().unwrap().remove(actor);
    }

    /// Publish an event to all subscribed actors
    pub fn publish(&self, event: BusEventEnvelope) {
        let _ = self.broadcast.send(event);
    }

    /// Publish a domain event
    pub fn publish_domain(&self, event: DomainEvent) {
        self.publish(BusEventEnvelope::Domain(event));
    }

    /// Publish an ephemeral event
    pub fn publish_ephemeral(&self, event: EphemeralEvent) {
        self.publish(BusEventEnvelope::Ephemeral(event));
    }

    /// Receive from the broadcast channel
    pub fn broadcast_recv(&self) -> Result<BusEventEnvelope, std::sync::mpsc::RecvError> {
        self.broadcast.recv()
    }

    /// Try to receive from the broadcast channel
    pub fn broadcast_try_recv(&self) -> Result<BusEventEnvelope, std::sync::mpsc::TryRecvError> {
        self.broadcast.try_recv()
    }

    /// Get the broadcast receiver
    pub fn broadcast_receiver(&self) -> Arc<Mutex<Receiver<BusEventEnvelope>>> {
        self.broadcast.receiver()
    }

    /// Register a typed channel for an actor
    pub fn register<T: Clone + Send + 'static>(&self, _actor: ActorId) -> ActorChannel<T> {
        ActorChannel::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_domain_events_are_tagged() {
        let event = DomainEvent::Submit { content: "test".into() };
        assert_eq!(event.tag(), EventTag::Domain);
    }

    #[test]
    fn test_ephemeral_events_are_tagged() {
        let event = EphemeralEvent::ScrollUp;
        assert_eq!(event.tag(), EventTag::Ephemeral);
    }

    #[test]
    fn test_event_envelope_tag() {
        let domain = BusEventEnvelope::Domain(DomainEvent::Submit { content: "test".into() });
        assert_eq!(domain.tag(), EventTag::Domain);

        let ephemeral = BusEventEnvelope::Ephemeral(EphemeralEvent::Input('a'));
        assert_eq!(ephemeral.tag(), EventTag::Ephemeral);
    }

    #[test]
    fn test_actor_channel_basic() {
        let channel: ActorChannel<String> = ActorChannel::new();
        channel.tx.send("hello".to_string()).unwrap();
        let received = channel.rx.recv().unwrap();
        assert_eq!(received, "hello");
    }

    #[test]
    fn test_subscription_filter_domain_only() {
        let filter = SubscriptionFilter::domain_only();
        let domain = BusEventEnvelope::Domain(DomainEvent::Submit { content: "test".into() });
        let ephemeral = BusEventEnvelope::Ephemeral(EphemeralEvent::ScrollUp);
        assert!(filter.matches(&domain));
        assert!(!filter.matches(&ephemeral));
    }

    #[test]
    fn test_subscription_filter_ephemeral_only() {
        let filter = SubscriptionFilter::ephemeral_only();
        let domain = BusEventEnvelope::Domain(DomainEvent::Submit { content: "test".into() });
        let ephemeral = BusEventEnvelope::Ephemeral(EphemeralEvent::ScrollUp);
        assert!(!filter.matches(&domain));
        assert!(filter.matches(&ephemeral));
    }

    #[test]
    fn test_event_bus_publish_and_broadcast() {
        let bus = EventBus::new();
        bus.publish_domain(DomainEvent::Submit { content: "hello".into() });

        let received = bus.broadcast_recv().unwrap();
        match received {
            BusEventEnvelope::Domain(DomainEvent::Submit { content }) => {
                assert_eq!(content, "hello");
            }
            _ => panic!("Expected domain Submit event"),
        }
    }

    #[test]
    fn test_event_bus_ephemeral_publish() {
        let bus = EventBus::new();
        bus.publish_ephemeral(EphemeralEvent::ScrollUp);

        let received = bus.broadcast_recv().unwrap();
        match received {
            BusEventEnvelope::Ephemeral(EphemeralEvent::ScrollUp) => {}
            _ => panic!("Expected ephemeral ScrollUp event"),
        }
    }

    #[test]
    fn test_actor_id_display() {
        assert_eq!(ActorId::AgentLoop.to_string(), "AgentLoop");
        assert_eq!(ActorId::SessionManager.to_string(), "SessionManager");
        assert_eq!(
            ActorId::ToolActor { name: "bash".into() }.to_string(),
            "ToolActor(bash)"
        );
    }

    #[test]
    fn test_event_bus_clone() {
        let bus1 = EventBus::new();
        let bus2 = bus1.clone();
        bus1.publish_domain(DomainEvent::SpawnAgent);
        assert!(bus2.broadcast_try_recv().is_ok());
    }

    #[test]
    fn test_broadcast_channel_arc_mutex() {
        let channel = BroadcastChannel::new();
        let receiver = channel.receiver();
        channel.send(BusEventEnvelope::Domain(DomainEvent::SpawnAgent)).unwrap();
        assert!(receiver.lock().unwrap().recv().is_ok());
    }
}

//! Session Manager — persists domain events to JSONL, handles session lifecycle.
//!
//! Architecture:
//!   - Subscribes to domain events from the event bus
//!   - Appends events to JSONL file on each domain event
//!   - Supports session load/replay/list/delete
//!   - Periodic snapshots as load accelerators

mod commands;
pub use commands::{SessionCmd, SessionResponse};

mod state;
pub use state::SessionState;

pub use crate::session_jsonl::{SessionMeta, list_session_names, load_session as load, delete_session as delete};

use std::path::PathBuf;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::time::Duration;

use crate::event_bus::{ActorChannel, BusEventEnvelope, DomainEvent, EventBus};
use crate::session_jsonl as jsonl;

// ---------------------------------------------------------------------------
// Session Manager Actor
// ---------------------------------------------------------------------------

/// Run the session manager actor loop.
/// Returns when shutdown flag is set or channel closes.
pub fn run_session_manager(
    _bus: EventBus,
    channel: ActorChannel<BusEventEnvelope>,
    shutdown: Arc<AtomicBool>,
    snapshot_interval: Duration,
) {
    let mut state = SessionState::default();

    while !shutdown.load(Ordering::SeqCst) {
        // Check for events (non-blocking)
        if let Ok(event) = channel.rx.try_recv() {
            match event {
                BusEventEnvelope::Domain(domain_event) => {
                    if let Err(e) = state.record_event(&domain_event) {
                        eprintln!("SessionManager: failed to record event: {}", e);
                    }
                }
                BusEventEnvelope::Ephemeral(_) => {
                    // Ephemeral events are not persisted
                }
            }
        }

        // Check if snapshot is needed
        if state.needs_snapshot(snapshot_interval) && state.has_active_session() {
            if let Err(e) = state.flush() {
                eprintln!("SessionManager: failed to snapshot: {}", e);
            } else {
                state.mark_snapshot();
            }
        }

        // Small sleep to avoid busy loop
        std::thread::sleep(Duration::from_millis(10));
    }

    // Cleanup on shutdown
    if let Err(e) = state.close_session() {
        eprintln!("SessionManager: failed to close session on shutdown: {}", e);
    }
}

// ---------------------------------------------------------------------------
// Convenience Functions
// ---------------------------------------------------------------------------

/// List all saved session names
pub fn list_sessions() -> anyhow::Result<Vec<String>> {
    jsonl::list_session_names()
}

/// Load a session by name, returning metadata and events
pub fn load_session(name: &str) -> anyhow::Result<(SessionMeta, Vec<DomainEvent>)> {
    jsonl::load_session(name)
}

/// Delete a session by name
pub fn delete_session(name: &str) -> anyhow::Result<()> {
    jsonl::delete_session(name)
}

/// Get the path for a session
pub fn session_path(name: &str) -> Option<PathBuf> {
    jsonl::session_path(name)
}

/// Start a new session and return the writer
pub fn start_session(
    name: &str,
    provider: &str,
    model: &str,
) -> anyhow::Result<(SessionMeta, jsonl::JsonlWriter)> {
    let path = session_path(name)
        .ok_or_else(|| anyhow::anyhow!("No sessions directory"))?;

    // Ensure directory exists
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent)?;
    }

    let meta = SessionMeta::new(name.to_string(), provider.to_string(), model.to_string());
    let writer = jsonl::JsonlWriter::create(&path, &meta)?;

    Ok((meta, writer))
}

