//! Actor implementations for runie
//!
//! These actors handle specific responsibilities in the application:
//! - ToolActor: Executes tools asynchronously
//! - QueueAgent: Manages the message queue and spawns agent when idle
//! - SessionManager: Persists domain events to JSONL
//! - ConfigAgent: Watches config files for changes

mod config_agent;
mod queue_agent;
mod session_manager;
mod tool_actor;

pub use config_agent::run_config_agent;
pub use queue_agent::run_queue_agent;
pub use session_manager::{run_session_manager, SessionState};
pub use tool_actor::run_tool_actor;

//! ToolActor — Executes tools asynchronously and emits ToolEnd events
//!
//! Each tool invocation spawns a dedicated ToolActor. The actor:
//! - Receives tool definition via channel
//! - Executes the tool (blocking) in a dedicated thread
//! - Emits ToolEnd event on completion

use crate::event_bus::{ActorChannel, BusEventEnvelope, DomainEvent, EventBus};
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::thread;
use std::time::Instant;

/// Tool invocation message for ToolActor
#[derive(Debug, Clone)]
pub struct ToolInvocation {
    pub id: String,
    pub name: String,
    pub params: serde_json::Value,
}

/// Run a ToolActor until shutdown or channel close.
///
/// The actor executes the tool in a blocking thread and emits:
/// - AgentToolStart on begin
/// - AgentToolEnd on completion
pub fn run_tool_actor(
    bus: EventBus,
    channel: ActorChannel<BusEventEnvelope>,
    invocation: ToolInvocation,
    shutdown: Arc<AtomicBool>,
) {
    let tool_name = invocation.name.clone();
    let tool_id = invocation.id.clone();

    // Emit ToolStart
    bus.publish_domain(DomainEvent::AgentToolStart {
        id: tool_id.clone(),
        name: tool_name.clone(),
    });

    let tool_start = Instant::now();

    // Execute tool in a blocking thread (tools can be slow)
    let result = thread::spawn(move || {
        execute_tool(&invocation)
    }).join().unwrap_or_else(|_| ToolOutput {
        success: false,
        output: "Tool execution panicked".to_string(),
    });

    let duration_secs = tool_start.elapsed().as_secs_f64();

    // Emit ToolEnd
    bus.publish_domain(DomainEvent::AgentToolEnd {
        id: tool_id,
        name: tool_name,
        duration_secs,
        output: result.output,
    });

    // Signal shutdown complete
    shutdown.store(true, Ordering::SeqCst);
}

/// Tool execution output
#[derive(Debug, Clone)]
pub struct ToolOutput {
    pub success: bool,
    pub output: String,
}

/// Execute a tool by name with parameters
fn execute_tool(invocation: &ToolInvocation) -> ToolOutput {
    match invocation.name.as_str() {
        "read_file" => execute_read_file(&invocation.params),
        "list_dir" => execute_list_dir(&invocation.params),
        "write_file" => execute_write_file(&invocation.params),
        "edit_file" => execute_edit_file(&invocation.params),
        "bash" => execute_bash(&invocation.params),
        "grep" => execute_grep(&invocation.params),
        "find" => execute_find(&invocation.params),
        _ => ToolOutput {
            success: false,
            output: format!("Unknown tool: {}", invocation.name),
        },
    }
}

fn get_str(params: &serde_json::Value, key: &str) -> String {
    params.get(key).and_then(|v| v.as_str()).unwrap_or("").to_string()
}

fn get_opt_str(params: &serde_json::Value, key: &str) -> Option<String> {
    params.get(key).and_then(|v| v.as_str()).map(String::from)
}

fn get_usize(params: &serde_json::Value, key: &str, default: usize) -> usize {
    params.get(key).and_then(|v| v.as_u64()).map(|v| v as usize).unwrap_or(default)
}

fn get_bool(params: &serde_json::Value, key: &str) -> bool {
    params.get(key).and_then(|v| v.as_bool()).unwrap_or(false)
}

fn execute_read_file(params: &serde_json::Value) -> ToolOutput {
    let path = get_str(params, "path");
    let offset = params.get("offset").and_then(|v| v.as_u64()).map(|v| v as usize);
    let limit = params.get("limit").and_then(|v| v.as_u64()).map(|v| v as usize);

    match std::fs::read_to_string(&path) {
        Ok(content) => {
            let lines: Vec<&str> = content.lines().collect();
            let total_lines = lines.len();
            let start = offset.unwrap_or(0).min(total_lines);
            let end = limit.map(|l| (start + l).min(total_lines)).unwrap_or(total_lines);

            if start >= total_lines {
                return ToolOutput { success: true, output: "(end of file)".to_string() };
            }

            let selected: String = lines[start..end].join("\n");
            let output = if offset.is_some() || limit.is_some() {
                format!("[Lines {}-{} of {}]\n{}", start + 1, end, total_lines, selected)
            } else {
                selected
            };

            let output = if end < total_lines {
                format!("{}\n[{} more lines]", output, total_lines - end)
            } else {
                output
            };

            ToolOutput { success: true, output }
        }
        Err(e) => ToolOutput {
            success: false,
            output: format!("Error reading {}: {}", path, e),
        },
    }
}

fn execute_list_dir(params: &serde_json::Value) -> ToolOutput {
    let path = get_str(params, "path");
    match std::fs::read_dir(&path) {
        Ok(entries) => {
            let mut lines: Vec<String> = Vec::new();
            for entry in entries.flatten() {
                let name = entry.file_name().to_string_lossy().to_string();
                let typ = if entry.file_type().map(|t| t.is_dir()).unwrap_or(false) {
                    "dir"
                } else {
                    "file"
                };
                lines.push(format!("{} ({})", name, typ));
            }
            let output = if lines.is_empty() {
                "(empty directory)".to_string()
            } else {
                lines.join("\n")
            };
            ToolOutput { success: true, output }
        }
        Err(e) => ToolOutput {
            success: false,
            output: format!("Error listing {}: {}", path, e),
        },
    }
}

fn execute_write_file(params: &serde_json::Value) -> ToolOutput {
    let path = get_str(params, "path");
    let content = get_str(params, "content");

    // Create parent directories if needed
    if let Some(parent) = std::path::Path::new(&path).parent() {
        if !parent.as_os_str().is_empty() {
            if let Err(e) = std::fs::create_dir_all(parent) {
                return ToolOutput {
                    success: false,
                    output: format!("Error creating parent directories: {}", e),
                };
            }
        }
    }

    match std::fs::write(&path, &content) {
        Ok(()) => ToolOutput {
            success: true,
            output: format!("Wrote {} bytes to {}", content.len(), path),
        },
        Err(e) => ToolOutput {
            success: false,
            output: format!("Error writing {}: {}", path, e),
        },
    }
}

fn execute_edit_file(params: &serde_json::Value) -> ToolOutput {
    let path = get_str(params, "path");
    let search = get_str(params, "search");
    let replace = get_str(params, "replace");

    if search.is_empty() {
        return ToolOutput {
            success: false,
            output: "Error: search text cannot be empty".to_string(),
        };
    }

    match std::fs::read_to_string(&path) {
        Ok(content) => {
            let count = content.matches(&search).count();
            if count == 0 {
                return ToolOutput {
                    success: false,
                    output: format!("Error: search text not found in {}", path),
                };
            }
            if count > 1 {
                return ToolOutput {
                    success: false,
                    output: format!(
                        "Error: search text appears {} times in {}. Be more specific.",
                        count, path
                    ),
                };
            }
            let new_content = content.replacen(&search, &replace, 1);
            match std::fs::write(&path, &new_content) {
                Ok(()) => {
                    let diff = crate::diff::generate_unified_diff(&content, &new_content);
                    let output = crate::diff::render_diff_to_string(&diff, &path);
                    ToolOutput { success: true, output }
                }
                Err(e) => ToolOutput {
                    success: false,
                    output: format!("Error writing {}: {}", path, e),
                },
            }
        }
        Err(e) => ToolOutput {
            success: false,
            output: format!("Error reading {}: {}", path, e),
        },
    }
}

fn execute_bash(params: &serde_json::Value) -> ToolOutput {
    let command = get_str(params, "command");

    // Safety check
    if let Some(reason) = crate::update::bash::check_bash_safety(&command) {
        return ToolOutput {
            success: false,
            output: format!("Blocked: {}", reason),
        };
    }

    let timeout_secs = get_usize(params, "timeout", 60);
    let output = run_bash_with_timeout(&command, std::time::Duration::from_secs(timeout_secs as u64));

    match output {
        Ok(out) => {
            let mut result = String::new();
            if !out.stdout.is_empty() {
                result.push_str(&String::from_utf8_lossy(&out.stdout));
            }
            if !out.stderr.is_empty() {
                if !result.is_empty() {
                    result.push('\n');
                }
                result.push_str(&String::from_utf8_lossy(&out.stderr));
            }
            let success = out.status.success();
            if result.is_empty() {
                result = if success {
                    "(no output)".to_string()
                } else {
                    "(command failed)".to_string()
                };
            }
            ToolOutput { success, output: result }
        }
        Err(e) => ToolOutput {
            success: false,
            output: format!("Error executing '{}': {}", command, e),
        },
    }
}

fn run_bash_with_timeout(command: &str, timeout: std::time::Duration) -> std::io::Result<std::process::Output> {
    use std::process::Command;
    use std::sync::mpsc;

    let (tx, rx) = mpsc::channel();

    let cmd = command.to_string();
    thread::spawn(move || {
        match Command::new("bash").arg("-c").arg(&cmd).output() {
            Ok(output) => { let _ = tx.send(Ok(output)); }
            Err(e) => { let _ = tx.send(Err(e)); }
        }
    });

    match rx.recv_timeout(timeout) {
        Ok(result) => result,
        Err(mpsc::RecvTimeoutError::Timeout) => {
            Err(std::io::Error::new(
                std::io::ErrorKind::TimedOut,
                format!("Command timed out after {:?}", timeout)
            ))
        }
        Err(mpsc::RecvTimeoutError::Disconnected) => {
            Err(std::io::Error::other("Channel disconnected unexpectedly"))
        }
    }
}

fn execute_grep(params: &serde_json::Value) -> ToolOutput {
    let pattern = get_str(params, "pattern");
    let path = get_str(params, "path");
    let glob = get_opt_str(params, "glob");
    let ignore_case = get_bool(params, "ignore_case");
    let literal = get_bool(params, "literal");
    let context = get_usize(params, "context", 0);
    let limit = get_usize(params, "limit", 100);

    let tool = if which_tool("rg").is_some() { "rg" } else { "grep" };

    let mut args = vec!["--line-number", "--color=never", "--hidden"];
    if ignore_case { args.push("--ignore-case"); }
    if literal { args.push("--fixed-strings"); }
    if let Some(ref g) = glob { args.push("--glob"); args.push(g); }
    if context > 0 {
        args.push("--context");
        args.push(&context.to_string());
    }
    args.push("--max-count");
    args.push(&limit.to_string());
    args.push("--");
    args.push(&pattern);
    args.push(&path);

    match std::process::Command::new(tool).args(&args).output() {
        Ok(output) => {
            let text = String::from_utf8_lossy(&output.stdout);
            let err = String::from_utf8_lossy(&output.stderr);
            if text.trim().is_empty() {
                if output.status.code() == Some(1) {
                    return ToolOutput { success: true, output: "No matches found".to_string() };
                }
                return ToolOutput {
                    success: false,
                    output: format!("Error: {}", err.trim()),
                };
            }
            let mut result = text.to_string();
            let lines: Vec<&str> = text.lines().collect();
            if lines.len() >= limit {
                result.push_str(&format!("\n\n[{} matches limit reached]", limit));
            }
            ToolOutput { success: true, output: result }
        }
        Err(e) => ToolOutput {
            success: false,
            output: format!("Error running grep: {}", e),
        },
    }
}

fn execute_find(params: &serde_json::Value) -> ToolOutput {
    let pattern = get_str(params, "pattern");
    let path = get_str(params, "path");
    let limit = get_usize(params, "limit", 100);

    let tool = if which_tool("fd").is_some() { "fd" } else { "find" };

    let output = if tool == "fd" {
        let args = &[
            "--glob", "--color=never", "--hidden", "--no-require-git",
            "--max-results", &limit.to_string(),
            "--", &pattern, &path,
        ];
        std::process::Command::new(tool).args(args).output()
    } else {
        let args = &[
            &path, "-maxdepth", "10", "-path", &format!("*/{}", pattern),
        ];
        std::process::Command::new(tool).args(args).output()
    };

    match output {
        Ok(output) => {
            let text = String::from_utf8_lossy(&output.stdout);
            if text.trim().is_empty() {
                return ToolOutput {
                    success: true,
                    output: "No files found matching pattern".to_string(),
                };
            }
            let lines: Vec<&str> = text.lines().collect();
            let mut out = lines[..limit.min(lines.len())].join("\n");
            if lines.len() > limit {
                out.push_str(&format!("\n\n[{} results limit reached]", limit));
            }
            ToolOutput { success: true, output: out }
        }
        Err(e) => ToolOutput {
            success: false,
            output: format!("Error running find: {}", e),
        },
    }
}

fn which_tool(name: &str) -> Option<String> {
    std::process::Command::new("which")
        .arg(name)
        .output()
        .ok()
        .filter(|o| o.status.success())
        .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string())
}

