//! ConfigAgent — Watches config files for changes and emits ConfigChanged events
//!
//! The ConfigAgent monitors the configuration file and emits domain events
//! when changes are detected, allowing actors to apply new settings
//! without requiring a restart.

use std::collections::HashMap;
use std::fs;
use std::path::PathBuf;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::time::{Duration, Instant};

use crate::event_bus::{ActorChannel, BusEventEnvelope, DomainEvent, EventBus};

/// Configuration change event
#[derive(Debug, Clone)]
pub struct ConfigChanged {
    pub path: PathBuf,
    pub changes: HashMap<String, ConfigValue>,
}

/// Configuration value types
#[derive(Debug, Clone)]
pub enum ConfigValue {
    String(String),
    Integer(i64),
    Float(f64),
    Boolean(bool),
    Array(Vec<ConfigValue>),
    Object(HashMap<String, ConfigValue>),
}

impl ConfigValue {
    /// Parse a TOML value into ConfigValue
    pub fn from_toml(value: &toml::Value) -> Self {
        match value {
            toml::Value::String(s) => ConfigValue::String(s.clone()),
            toml::Value::Integer(i) => ConfigValue::Integer(*i),
            toml::Value::Float(f) => ConfigValue::Float(*f),
            toml::Value::Boolean(b) => ConfigValue::Boolean(*b),
            toml::Value::Datetime(dt) => ConfigValue::String(dt.to_string()),
            toml::Value::Array(arr) => {
                ConfigValue::Array(arr.iter().map(ConfigValue::from_toml).collect())
            }
            toml::Value::Table(table) => {
                let mut map = HashMap::new();
                for (k, v) in table {
                    map.insert(k.clone(), ConfigValue::from_toml(v));
                }
                ConfigValue::Object(map)
            }
        }
    }
}

/// Config file state for change detection
#[derive(Debug, Clone)]
struct ConfigFileState {
    path: PathBuf,
    last_modified: Option<Instant>,
    last_hash: Option<u64>,
}

impl ConfigFileState {
    fn new(path: PathBuf) -> Self {
        Self {
            path,
            last_modified: None,
            last_hash: None,
