        let metadata = match fs::metadata(&self.path) {
            Ok(m) => m,
            Err(_) => return None,
        };

        let modified = metadata.modified().ok()?;
        let modified_instant = Instant::now() - modified.elapsed();

        // Check if modified time changed
        let time_changed = self
            .last_modified
            .map(|t| t != modified_instant)
            .unwrap_or(true);

