//! ToolActor — Executes tools asynchronously and emits ToolEnd events
//!
//! Each tool invocation spawns a dedicated ToolActor. The actor:
//! - Receives tool definition via channel
//! - Executes the tool (blocking) in a dedicated thread
//! - Emits ToolEnd event on completion

mod tool_execute;
pub use tool_execute::ToolInvocation;

use crate::event_bus::{ActorChannel, BusEventEnvelope, DomainEvent, EventBus};
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::time::Instant;

/// Tool execution output
#[derive(Debug, Clone)]
pub struct ToolOutput {
    pub success: bool,
    pub output: String,
}

/// Run a ToolActor until shutdown or channel close.
///
/// The actor executes the tool in a blocking thread and emits:
/// - AgentToolStart on begin
/// - AgentToolEnd on completion
pub fn run_tool_actor(
    bus: EventBus,
    _channel: ActorChannel<BusEventEnvelope>,
    invocation: ToolInvocation,
    shutdown: Arc<AtomicBool>,
) {
    let tool_name = invocation.name.clone();
    let tool_id = invocation.id.clone();

    // Emit ToolStart
    bus.publish_domain(DomainEvent::AgentToolStart {
        id: tool_id.clone(),
        name: tool_name.clone(),
    });

    let tool_start = Instant::now();

    // Execute tool in a blocking thread (tools can be slow)
    let result = std::thread::spawn(move || {
        tool_execute::execute_tool(&invocation)
    }).join().unwrap_or(ToolOutput {
        success: false,
        output: "Tool execution panicked".to_string(),
    });

    let duration_secs = tool_start.elapsed().as_secs_f64();

    // Emit ToolEnd
    bus.publish_domain(DomainEvent::AgentToolEnd {
        id: tool_id,
        name: tool_name,
        duration_secs,
        output: result.output,
    });

    // Signal shutdown complete
    shutdown.store(true, Ordering::SeqCst);
}

//! Tool execution logic

use std::path::Path;
use std::process::Command;
use std::sync::mpsc;
use std::thread;

/// Tool invocation message for ToolActor
#[derive(Debug, Clone)]
pub struct ToolInvocation {
    pub id: String,
    pub name: String,
    pub params: serde_json::Value,
}

/// Execute a tool by name with parameters
pub fn execute_tool(invocation: &ToolInvocation) -> super::ToolOutput {
    match invocation.name.as_str() {
        "read_file" => execute_read_file(&invocation.params),
        "list_dir" => execute_list_dir(&invocation.params),
        "write_file" => execute_write_file(&invocation.params),
        "edit_file" => execute_edit_file(&invocation.params),
        "bash" => execute_bash(&invocation.params),
        "grep" => execute_grep(&invocation.params),
        "find" => execute_find(&invocation.params),
        _ => super::ToolOutput {
            success: false,
            output: format!("Unknown tool: {}", invocation.name),
        },
    }
}

// ============================================================================
// Bash safety and execution
// ============================================================================

/// Check if a bash command is safe to execute
fn check_bash_safety(command: &str) -> Option<&'static str> {
    let cmd = command.trim().to_lowercase();
    if cmd.contains("rm -rf /") || cmd.contains("rm -rf /*") || cmd.contains("rm -rf ~") {
        return Some("rm -rf on system directories or home is blocked");
    }
    if cmd.starts_with("dd ") && cmd.contains("of=/dev/") {
        return Some("dd writing to block devices is blocked");
    }
    if cmd.contains("> /dev/sda") || cmd.contains("> /dev/nvme") || cmd.contains("> /dev/hd") {
        return Some("writing directly to block devices is blocked");
    }
    if cmd.starts_with("mkfs") || cmd.starts_with("mkfs.") {
        return Some("mkfs is blocked");
    }
    if cmd.contains(":|:") && cmd.contains("};") {
        return Some("fork bombs are blocked");
    }
    if cmd.contains("chmod -r 777 /") || cmd.contains("chmod -r 000 /") {
        return Some("recursive chmod on root is blocked");
    }
    if cmd.starts_with("sudo ") && (cmd.contains(" rm ") || cmd.contains(" dd ")) {
        return Some("sudo with destructive commands is blocked");
    }
    None
}

/// Run bash command with timeout
fn run_bash_with_timeout(command: &str, timeout: std::time::Duration) -> std::io::Result<std::process::Output> {
    let (tx, rx) = mpsc::channel();
    let cmd = command.to_string();
    thread::spawn(move || {
        match Command::new("bash").arg("-c").arg(&cmd).output() {
            Ok(output) => { let _ = tx.send(Ok(output)); }
            Err(e) => { let _ = tx.send(Err(e)); }
        }
    });

    match rx.recv_timeout(timeout) {
        Ok(result) => result,
        Err(mpsc::RecvTimeoutError::Timeout) => {
            Err(std::io::Error::new(
                std::io::ErrorKind::TimedOut,
                format!("Command timed out after {:?}", timeout)
            ))
        }
        Err(mpsc::RecvTimeoutError::Disconnected) => {
            Err(std::io::Error::other("Channel disconnected unexpectedly"))
        }
    }
}

// ============================================================================
// Tool implementations
// ============================================================================

fn get_str(params: &serde_json::Value, key: &str) -> String {
    params.get(key).and_then(|v| v.as_str()).unwrap_or("").to_string()
}

fn get_usize(params: &serde_json::Value, key: &str, default: usize) -> usize {
    params.get(key).and_then(|v| v.as_u64()).map(|v| v as usize).unwrap_or(default)
}

fn get_bool(params: &serde_json::Value, key: &str) -> bool {
    params.get(key).and_then(|v| v.as_bool()).unwrap_or(false)
}

fn truncate_text(text: &str, max_len: usize) -> String {
    if text.len() <= max_len {
        text.to_string()
    } else {
        format!("{}...", &text[..max_len.saturating_sub(3)])
    }
}

// --- read_file ---------------------------------------------------------------

fn execute_read_file(params: &serde_json::Value) -> super::ToolOutput {
    let path = get_str(params, "path");
    let offset = params.get("offset").and_then(|v| v.as_u64()).map(|v| v as usize);
    let limit = params.get("limit").and_then(|v| v.as_u64()).map(|v| v as usize);

    match std::fs::read_to_string(&path) {
        Ok(content) => read_file_content(&path, &content, offset, limit),
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error reading {}: {}", path, e),
        },
    }
}

fn read_file_content(path: &str, content: &str, offset: Option<usize>, limit: Option<usize>) -> super::ToolOutput {
    let lines: Vec<&str> = content.lines().collect();
    let total_lines = lines.len();
    let start = offset.unwrap_or(0).min(total_lines);
    let end = limit.map(|l| (start + l).min(total_lines)).unwrap_or(total_lines);

    if start >= total_lines {
        return super::ToolOutput { success: true, output: "(end of file)".to_string() };
    }

    let selected: String = lines[start..end].join("\n");
    let output = if offset.is_some() || limit.is_some() {
        format!("[Lines {}-{} of {}]\n{}", start + 1, end, total_lines, selected)
    } else {
        selected
    };

    let output = if end < total_lines {
        format!("{}\n[{} more lines]", output, total_lines - end)
    } else {
        output
    };

    super::ToolOutput { success: true, output }
}

// --- list_dir ----------------------------------------------------------------

fn execute_list_dir(params: &serde_json::Value) -> super::ToolOutput {
    let path = get_str(params, "path");
    match std::fs::read_dir(&path) {
        Ok(entries) => {
            let mut lines: Vec<String> = Vec::new();
            for entry in entries.flatten() {
                let name = entry.file_name().to_string_lossy().to_string();
                let typ = if entry.file_type().map(|t| t.is_dir()).unwrap_or(false) {
                    "dir"
                } else {
                    "file"
                };
                lines.push(format!("{} ({})", name, typ));
            }
            let output = if lines.is_empty() {
                "(empty directory)".to_string()
            } else {
                lines.join("\n")
            };
            super::ToolOutput { success: true, output }
        }
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error listing {}: {}", path, e),
        },
    }
}

// --- write_file --------------------------------------------------------------

fn execute_write_file(params: &serde_json::Value) -> super::ToolOutput {
    let path = get_str(params, "path");
    let content = get_str(params, "content");

    if let Some(parent) = Path::new(&path).parent() {
        if !parent.as_os_str().is_empty() {
            if let Err(e) = std::fs::create_dir_all(parent) {
                return super::ToolOutput {
                    success: false,
                    output: format!("Error creating parent directories: {}", e),
                };
            }
        }
    }

    match std::fs::write(&path, &content) {
        Ok(()) => super::ToolOutput {
            success: true,
            output: format!("Wrote {} bytes to {}", content.len(), path),
        },
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error writing {}: {}", path, e),
        },
    }
}

// --- edit_file ---------------------------------------------------------------

fn execute_edit_file(params: &serde_json::Value) -> super::ToolOutput {
    let path = get_str(params, "path");
    let search = get_str(params, "search");
    let replace = get_str(params, "replace");

    if search.is_empty() {
        return super::ToolOutput {
            success: false,
            output: "Error: search text cannot be empty".to_string(),
        };
    }

    match std::fs::read_to_string(&path) {
        Ok(content) => apply_edit(&path, &content, &search, &replace),
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error reading {}: {}", path, e),
        },
    }
}

fn apply_edit(path: &str, content: &str, search: &str, replace: &str) -> super::ToolOutput {
    let count = content.matches(search).count();
    if count == 0 {
        return super::ToolOutput {
            success: false,
            output: format!("Error: search text not found in {}", path),
        };
    }
    if count > 1 {
        return super::ToolOutput {
            success: false,
            output: format!(
                "Error: search text appears {} times in {}. Be more specific.",
                count, path
            ),
        };
    }
    let new_content = content.replacen(search, replace, 1);
    match std::fs::write(path, &new_content) {
        Ok(()) => {
            let output = format!(
                "Edited {} successfully ({} -> \"{}\")",
                path,
                truncate_text(search, 30),
                truncate_text(replace, 30)
            );
            super::ToolOutput { success: true, output }
        }
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error writing {}: {}", path, e),
        },
    }
}

// --- bash --------------------------------------------------------------------

fn execute_bash(params: &serde_json::Value) -> super::ToolOutput {
    let command = get_str(params, "command");

    if let Some(reason) = check_bash_safety(&command) {
        return super::ToolOutput {
            success: false,
            output: format!("Blocked: {}", reason),
        };
    }

    let timeout_secs = get_usize(params, "timeout", 60);
    let output = run_bash_with_timeout(&command, std::time::Duration::from_secs(timeout_secs as u64));

    match output {
        Ok(out) => parse_bash_output(out),
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error executing '{}': {}", command, e),
        },
    }
}

fn parse_bash_output(out: std::process::Output) -> super::ToolOutput {
    let mut result = String::new();
    if !out.stdout.is_empty() {
        result.push_str(&String::from_utf8_lossy(&out.stdout));
    }
    if !out.stderr.is_empty() {
        if !result.is_empty() {
            result.push('\n');
        }
        result.push_str(&String::from_utf8_lossy(&out.stderr));
    }
    let success = out.status.success();
    if result.is_empty() {
        result = if success {
            "(no output)".to_string()
        } else {
            "(command failed)".to_string()
        };
    }
    super::ToolOutput { success, output: result }
}

// --- grep -------------------------------------------------------------------

fn execute_grep(params: &serde_json::Value) -> super::ToolOutput {
    let pattern = get_str(params, "pattern");
    let path = get_str(params, "path");
    let ignore_case = get_bool(params, "ignore_case");
    let literal = get_bool(params, "literal");
    let context = get_usize(params, "context", 0);
    let limit = get_usize(params, "limit", 100);

    let tool = which_tool("rg").unwrap_or_else(|| "grep".to_string());
    let args = build_grep_args(&pattern, &path, ignore_case, literal, context, limit);

    match Command::new(&tool).args(&args).output() {
        Ok(output) => parse_grep_output(output, limit),
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error running grep: {}", e),
        },
    }
}

fn build_grep_args(pattern: &str, path: &str, ignore_case: bool, literal: bool, context: usize, limit: usize) -> Vec<String> {
    let mut args = vec!["--line-number".to_string(), "--color=never".to_string(), "--hidden".to_string()];
    if ignore_case { args.push("--ignore-case".to_string()); }
    if literal { args.push("--fixed-strings".to_string()); }
    if context > 0 {
        args.push("--context".to_string());
        args.push(context.to_string());
    }
    args.push("--max-count".to_string());
    args.push(limit.to_string());
    args.push("--".to_string());
    args.push(pattern.to_string());
    args.push(path.to_string());
    args
}

fn parse_grep_output(output: std::process::Output, limit: usize) -> super::ToolOutput {
    let text = String::from_utf8_lossy(&output.stdout);
    let err = String::from_utf8_lossy(&output.stderr);
    if text.trim().is_empty() {
        if output.status.code() == Some(1) {
            return super::ToolOutput { success: true, output: "No matches found".to_string() };
        }
        return super::ToolOutput {
            success: false,
            output: format!("Error: {}", err.trim()),
        };
    }
    let mut result = text.to_string();
    let lines: Vec<&str> = text.lines().collect();
    if lines.len() >= limit {
        result.push_str(&format!("\n\n[{} matches limit reached]", limit));
    }
    super::ToolOutput { success: true, output: result }
}

// --- find -------------------------------------------------------------------

fn execute_find(params: &serde_json::Value) -> super::ToolOutput {
    let pattern = get_str(params, "pattern");
    let path = get_str(params, "path");
    let limit = get_usize(params, "limit", 100);

    let tool = if which_tool("fd").is_some() { "fd" } else { "find" };

    let output = if tool == "fd" {
        let args = &[
            "--glob", "--color=never", "--hidden", "--no-require-git",
            "--max-results", &limit.to_string(),
            "--", &pattern, &path,
        ];
        Command::new("fd").args(args).output()
    } else {
        let args = &[&path, "-maxdepth", "10", "-path", &format!("*/{}", pattern)];
        Command::new("find").args(args).output()
    };

    match output {
        Ok(output) => parse_find_output(output, limit),
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error running find: {}", e),
        },
    }
}

fn parse_find_output(output: std::process::Output, limit: usize) -> super::ToolOutput {
    let text = String::from_utf8_lossy(&output.stdout);
    if text.trim().is_empty() {
        return super::ToolOutput {
            success: true,
            output: "No files found matching pattern".to_string(),
        };
    }
    let lines: Vec<&str> = text.lines().collect();
    let mut out = lines[..limit.min(lines.len())].join("\n");
    if lines.len() > limit {
        out.push_str(&format!("\n\n[{} results limit reached]", limit));
    }
    super::ToolOutput { success: true, output: out }
}

// --- utils ------------------------------------------------------------------

fn which_tool(name: &str) -> Option<String> {
    Command::new("which")
        .arg(name)
        .output()
        .ok()
        .filter(|o| o.status.success())
        .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string())
}

// ============================================================================
// Tests
// ============================================================================

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn tool_invocation_serialization() {
        let inv = ToolInvocation {
            id: "test-1".to_string(),
            name: "bash".to_string(),
            params: serde_json::json!({"command": "echo hello"}),
        };
        let json = serde_json::to_string(&inv).unwrap();
        let parsed: ToolInvocation = serde_json::from_str(&json).unwrap();
        assert_eq!(parsed.name, "bash");
    }

    #[test]
    fn read_file_tool() {
        let temp_dir = std::env::temp_dir();
        let test_file = temp_dir.join("runie_test_read.txt");
        std::fs::write(&test_file, "line 1\nline 2\nline 3\n").unwrap();

        let result = execute_tool(&ToolInvocation {
            id: "test".to_string(),
            name: "read_file".to_string(),
            params: serde_json::json!({"path": test_file.to_string_lossy()}),
        });
        assert!(result.success);
        assert!(result.output.contains("line 1"));

        let _ = std::fs::remove_file(test_file);
    }

    #[test]
    fn read_file_with_offset_limit() {
        let temp_dir = std::env::temp_dir();
        let test_file = temp_dir.join("runie_test_offset.txt");
        std::fs::write(&test_file, "line 1\nline 2\nline 3\nline 4\n").unwrap();

        let result = execute_read_file(&serde_json::json!({
            "path": test_file.to_string_lossy(),
            "offset": 1,
            "limit": 2
        }));
        assert!(result.success);
        assert!(result.output.contains("line 2"));
        assert!(result.output.contains("line 3"));

        let _ = std::fs::remove_file(test_file);
    }

    #[test]
    fn list_dir_tool() {
        let temp_dir = std::env::temp_dir().join("runie_test_list");
        std::fs::create_dir_all(&temp_dir).unwrap();
        std::fs::write(temp_dir.join("file.txt"), "").unwrap();
        std::fs::create_dir(temp_dir.join("subdir")).unwrap();

        let result = execute_list_dir(&serde_json::json!({
            "path": temp_dir.to_string_lossy()
        }));
        assert!(result.success);
        assert!(result.output.contains("file.txt"));

        let _ = std::fs::remove_dir_all(temp_dir);
    }

    #[test]
    fn write_file_tool() {
        let temp_dir = std::env::temp_dir();
        let test_file = temp_dir.join("runie_test_write.txt");

        let result = execute_write_file(&serde_json::json!({
            "path": test_file.to_string_lossy(),
            "content": "hello world"
        }));
        assert!(result.success);

        let content = std::fs::read_to_string(&test_file).unwrap();
        assert_eq!(content, "hello world");

        let _ = std::fs::remove_file(test_file);
    }

    #[test]
    fn bash_tool_echo() {
        let result = execute_bash(&serde_json::json!({"command": "echo hello"}));
        assert!(result.success);
        assert!(result.output.contains("hello"));
    }

    #[test]
    fn bash_tool_blocked() {
        let result = execute_bash(&serde_json::json!({"command": "rm -rf /"}));
        assert!(!result.success);
        assert!(result.output.contains("Blocked"));
    }

    #[test]
    fn unknown_tool() {
        let result = execute_tool(&ToolInvocation {
            id: "test".to_string(),
            name: "unknown_tool".to_string(),
            params: serde_json::json!({}),
        });
        assert!(!result.success);
        assert!(result.output.contains("Unknown tool"));
    }

    #[test]
    fn truncate_text_helper() {
        assert_eq!(truncate_text("hello", 10), "hello");
        assert_eq!(truncate_text("hello world", 8), "hello...");
        assert_eq!(truncate_text("hi", 10), "hi");
    }

    #[test]
    fn safety_allows_simple_commands() {
        assert!(check_bash_safety("echo hello").is_none());
        assert!(check_bash_safety("ls -la").is_none());
        assert!(check_bash_safety("pwd").is_none());
    }

    #[test]
    fn safety_blocks_rm_rf_root() {
        assert!(check_bash_safety("rm -rf /").is_some());
        assert!(check_bash_safety("rm -rf /*").is_some());
        assert!(check_bash_safety("rm -rf ~").is_some());
    }

    #[test]
    fn bash_timeout() {
        let result = run_bash_with_timeout("sleep 10", std::time::Duration::from_millis(100));
        assert!(result.is_err());
        assert!(result.unwrap_err().kind() == std::io::ErrorKind::TimedOut);
    }
}

