fn parse_bash_output(out: std::process::Output) -> super::ToolOutput {
    let mut result = String::new();
    if !out.stdout.is_empty() {
        result.push_str(&String::from_utf8_lossy(&out.stdout));
    }
    if !out.stderr.is_empty() {
        if !result.is_empty() {
            result.push('\n');
        }
