}

// --- find -------------------------------------------------------------------

fn execute_find(params: &serde_json::Value) -> super::ToolOutput {
    let pattern = get_str(params, "pattern");
    let path = get_str(params, "path");
    let limit = get_usize(params, "limit", 100);

