                "(empty directory)".to_string()
            } else {
                lines.join("\n")
            };
            super::ToolOutput { success: true, output }
        }
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error listing {}: {}", path, e),
        },
    }
}

// --- write_file --------------------------------------------------------------

fn execute_write_file(params: &serde_json::Value) -> super::ToolOutput {
    let path = get_str(params, "path");
    let content = get_str(params, "content");

    if let Some(parent) = Path::new(&path).parent() {
        if !parent.as_os_str().is_empty() {
            if let Err(e) = std::fs::create_dir_all(parent) {
                return super::ToolOutput {
                    success: false,
                    output: format!("Error creating parent directories: {}", e),
                };
            }
        }
    }

    match std::fs::write(&path, &content) {
        Ok(()) => super::ToolOutput {
            success: true,
            output: format!("Wrote {} bytes to {}", content.len(), path),
        },
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error writing {}: {}", path, e),
        },
    }
}

// --- edit_file ---------------------------------------------------------------

fn execute_edit_file(params: &serde_json::Value) -> super::ToolOutput {
    let path = get_str(params, "path");
    let search = get_str(params, "search");
    let replace = get_str(params, "replace");

    if search.is_empty() {
        return super::ToolOutput {
            success: false,
            output: "Error: search text cannot be empty".to_string(),
        };
    }

    match std::fs::read_to_string(&path) {
        Ok(content) => apply_edit(&path, &content, &search, &replace),
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error reading {}: {}", path, e),
        },
    }
}

fn apply_edit(path: &str, content: &str, search: &str, replace: &str) -> super::ToolOutput {
    let count = content.matches(search).count();
    if count == 0 {
        return super::ToolOutput {
            success: false,
            output: format!("Error: search text not found in {}", path),
        };
    }
    if count > 1 {
        return super::ToolOutput {
            success: false,
            output: format!(
                "Error: search text appears {} times in {}. Be more specific.",
                count, path
            ),
        };
    }
    let new_content = content.replacen(search, replace, 1);
    match std::fs::write(path, &new_content) {
        Ok(()) => {
            let output = format!(
                "Edited {} successfully ({} -> \"{}\")",
                path,
                truncate_text(search, 30),
                truncate_text(replace, 30)
            );
            super::ToolOutput { success: true, output }
        }
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error writing {}: {}", path, e),
        },
    }
}

// --- bash --------------------------------------------------------------------

fn execute_bash(params: &serde_json::Value) -> super::ToolOutput {
    let command = get_str(params, "command");

    if let Some(reason) = check_bash_safety(&command) {
        return super::ToolOutput {
            success: false,
            output: format!("Blocked: {}", reason),
        };
    }

    let timeout_secs = get_usize(params, "timeout", 60);
    let output = run_bash_with_timeout(&command, std::time::Duration::from_secs(timeout_secs as u64));

    match output {
        Ok(out) => parse_bash_output(out),
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error executing '{}': {}", command, e),
        },
    }
}

fn parse_bash_output(out: std::process::Output) -> super::ToolOutput {
    let mut result = String::new();
    if !out.stdout.is_empty() {
        result.push_str(&String::from_utf8_lossy(&out.stdout));
    }
    if !out.stderr.is_empty() {
        if !result.is_empty() {
            result.push('\n');
        }
        result.push_str(&String::from_utf8_lossy(&out.stderr));
    }
    let success = out.status.success();
    if result.is_empty() {
        result = if success {
            "(no output)".to_string()
        } else {
            "(command failed)".to_string()
        };
    }
    super::ToolOutput { success, output: result }
}

// --- grep -------------------------------------------------------------------

fn execute_grep(params: &serde_json::Value) -> super::ToolOutput {
    let pattern = get_str(params, "pattern");
    let path = get_str(params, "path");
    let ignore_case = get_bool(params, "ignore_case");
    let literal = get_bool(params, "literal");
    let context = get_usize(params, "context", 0);
    let limit = get_usize(params, "limit", 100);

    let tool = which_tool("rg").unwrap_or_else(|| "grep".to_string());
    let args = build_grep_args(&pattern, &path, ignore_case, literal, context, limit);

    match Command::new(&tool).args(&args).output() {
        Ok(output) => parse_grep_output(output, limit),
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error running grep: {}", e),
        },
    }
}

fn build_grep_args(pattern: &str, path: &str, ignore_case: bool, literal: bool, context: usize, limit: usize) -> Vec<String> {
    let mut args = vec!["--line-number".to_string(), "--color=never".to_string(), "--hidden".to_string()];
    if ignore_case { args.push("--ignore-case".to_string()); }
    if literal { args.push("--fixed-strings".to_string()); }
    if context > 0 {
        args.push("--context".to_string());
        args.push(context.to_string());
    }
    args.push("--max-count".to_string());
    args.push(limit.to_string());
    args.push("--".to_string());
    args.push(pattern.to_string());
    args.push(path.to_string());
    args
}

fn parse_grep_output(output: std::process::Output, limit: usize) -> super::ToolOutput {
    let text = String::from_utf8_lossy(&output.stdout);
    let err = String::from_utf8_lossy(&output.stderr);
    if text.trim().is_empty() {
        if output.status.code() == Some(1) {
            return super::ToolOutput { success: true, output: "No matches found".to_string() };
        }
        return super::ToolOutput {
            success: false,
            output: format!("Error: {}", err.trim()),
        };
    }
    let mut result = text.to_string();
    let lines: Vec<&str> = text.lines().collect();
    if lines.len() >= limit {
        result.push_str(&format!("\n\n[{} matches limit reached]", limit));
    }
    super::ToolOutput { success: true, output: result }
}

// --- find -------------------------------------------------------------------

fn execute_find(params: &serde_json::Value) -> super::ToolOutput {
    let pattern = get_str(params, "pattern");
    let path = get_str(params, "path");
    let limit = get_usize(params, "limit", 100);

    let tool = if which_tool("fd").is_some() { "fd" } else { "find" };

    let output = if tool == "fd" {
        let args = &[
            "--glob", "--color=never", "--hidden", "--no-require-git",
            "--max-results", &limit.to_string(),
            "--", &pattern, &path,
        ];
        Command::new("fd").args(args).output()
    } else {
        let args = &[&path, "-maxdepth", "10", "-path", &format!("*/{}", pattern)];
        Command::new("find").args(args).output()
    };

    match output {
        Ok(output) => parse_find_output(output, limit),
        Err(e) => super::ToolOutput {
            success: false,
            output: format!("Error running find: {}", e),
        },
    }
}

fn parse_find_output(output: std::process::Output, limit: usize) -> super::ToolOutput {
    let text = String::from_utf8_lossy(&output.stdout);
    if text.trim().is_empty() {
        return super::ToolOutput {
            success: true,
            output: "No files found matching pattern".to_string(),
        };
    }
    let lines: Vec<&str> = text.lines().collect();
    let mut out = lines[..limit.min(lines.len())].join("\n");
    if lines.len() > limit {
        out.push_str(&format!("\n\n[{} results limit reached]", limit));
    }
    super::ToolOutput { success: true, output: out }
}

// --- utils ------------------------------------------------------------------

fn which_tool(name: &str) -> Option<String> {
    Command::new("which")
        .arg(name)
        .output()
        .ok()
        .filter(|o| o.status.success())
        .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string())
}

