/// Queue delivery mode
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum QueueMode {
    /// Process one request at a time
    Sequential,
    /// Process multiple requests concurrently (default)
    Concurrent,
}

impl Default for QueueMode {
    fn default() -> Self {
        QueueMode::Concurrent
    }
}

/// Request entry in the queue
#[derive(Debug, Clone)]
pub struct QueuedRequest {
    pub content: String,
    pub request_id: String,
    pub provider: String,
    pub model: String,
}

/// Queue agent state
#[derive(Debug, Default)]
pub struct QueueState {
    /// Pending requests
    pub queue: VecDeque<QueuedRequest>,
    /// Delivery mode
    pub mode: QueueMode,
    /// Number of in-flight requests
    pub inflight: usize,
    /// Maximum concurrent requests
    pub max_concurrent: usize,
}

impl QueueState {
    /// Add a request to the queue
    pub fn enqueue(&mut self, request: QueuedRequest) {
        self.queue.push_back(request);
    }

    /// Get the next request if allowed by concurrency limits
