use unicode_segmentation::UnicodeSegmentation;
use super::*;

// === Grapheme helpers ===

fn prev_grapheme_boundary(s: &str, pos: usize) -> usize {
    let mut last = 0;
    for (i, _) in s.grapheme_indices(true) {
        if i >= pos { break; }
        last = i;
    }
    last
}

fn next_grapheme_boundary(s: &str, pos: usize) -> usize {
    for (i, _) in s.grapheme_indices(true) {
        if i > pos { return i; }
    }
    s.len()
}

// === Word boundary helpers ===

fn find_word_boundary_left(s: &str, pos: usize) -> usize {
    let mut pos = pos;
    while pos > 0 {
        let prev = prev_grapheme_boundary(s, pos);
        if &s[prev..pos] != " " { break; }
        pos = prev;
    }
    while pos > 0 {
        let prev = prev_grapheme_boundary(s, pos);
        if &s[prev..pos] == " " { break; }
        pos = prev;
    }
    pos
}

fn find_word_boundary_right(s: &str, pos: usize) -> usize {
    let mut pos = pos;
    let len = s.len();
    while pos < len {
        let next = next_grapheme_boundary(s, pos);
        if &s[pos..next] == " " { break; }
        pos = next;
    }
    while pos < len {
        let next = next_grapheme_boundary(s, pos);
        if &s[pos..next] != " " { break; }
        pos = next;
    }
    pos
}

impl AppState {
    pub fn hint_text(&self) -> String {
        let mut parts = Vec::new();
        parts.push("Ctrl+Shift+E=expand/collapse".to_string());
        if self.at_suggestions.is_some() {
            parts.push("Tab=cycle".to_string());
            parts.push("Enter=insert".to_string());
            parts.push("Esc=close".to_string());
        } else if self.turn_active {
            parts.push("Enter=steer".to_string());
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=abort".to_string());
        } else if !self.input.is_empty() {
            parts.push("Enter=send".to_string());
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=clear".to_string());
        } else {
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=clear".to_string());
        }
        parts.push("Ctrl+C=quit".to_string());
        parts.join(" | ")
    }

    // === Cursor Movement (grapheme-aware) ===

    pub(crate) fn cursor_left(&mut self) {
        if self.cursor_pos > 0 {
            self.cursor_pos = prev_grapheme_boundary(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_right(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.cursor_pos = next_grapheme_boundary(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_start(&mut self) {
        if self.cursor_pos != 0 {
            self.cursor_pos = 0;
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_end(&mut self) {
        if self.cursor_pos != self.input.len() {
            self.cursor_pos = self.input.len();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    // === Word Navigation ===

    pub(crate) fn cursor_word_left(&mut self) {
        if self.cursor_pos > 0 {
            self.cursor_pos = find_word_boundary_left(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_word_right(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.cursor_pos = find_word_boundary_right(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    // === Text Editing ===

    pub(crate) fn insert_char(&mut self, c: char) {
        self.push_undo();
        if self.cursor_pos == self.input.len() {
            self.input.push(c);
        } else {
            self.input.insert(self.cursor_pos, c);
        }
        self.cursor_pos += c.len_utf8();
        self.clear_redo();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    pub(crate) fn delete_before_cursor(&mut self) {
        if self.cursor_pos > 0 {
            // Check if the character before cursor is a newline
            let char_before_cursor = self.input[..self.cursor_pos].chars().last();
            if char_before_cursor == Some('\n') {
                // Remove the newline character (join lines)
                self.push_undo();
                let new_pos = self.cursor_pos - 1; // Position after removing newline
                self.input.remove(self.cursor_pos - 1);
                self.cursor_pos = new_pos;
                self.clear_redo();
                self.handle_at_trigger();
                self.mark_dirty();
            } else {
                // Normal delete - remove grapheme before cursor
                self.push_undo();
                let new_pos = prev_grapheme_boundary(&self.input, self.cursor_pos);
                self.input.drain(new_pos..self.cursor_pos);
                self.cursor_pos = new_pos;
                self.clear_redo();
                self.handle_at_trigger();
                self.mark_dirty();
            }
        } else if self.cursor_pos == 0 && !self.input.is_empty() {
            // Cursor at absolute start - check if there's a newline
            if self.input.starts_with('\n') {
                self.push_undo();
                self.input.remove(0);
                self.clear_redo();
                self.handle_at_trigger();
                self.mark_dirty();
            } else {
                self.input_flash = 3;
            }
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn delete_word(&mut self) {
        if self.cursor_pos == 0 {
            self.input_flash = 3;
            return;
        }
        self.push_undo();
        let start = find_word_boundary_left(&self.input, self.cursor_pos);
        self.input.drain(start..self.cursor_pos);
        self.cursor_pos = start;
        self.clear_redo();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    pub(crate) fn delete_to_end(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.push_undo();
            self.input.truncate(self.cursor_pos);
            self.clear_redo();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn delete_to_start(&mut self) {
        if self.cursor_pos > 0 {
            self.push_undo();
            self.input.drain(..self.cursor_pos);
            self.cursor_pos = 0;
            self.clear_redo();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn kill_char(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.push_undo();
            let end = next_grapheme_boundary(&self.input, self.cursor_pos);
            self.input.drain(self.cursor_pos..end);
            self.clear_redo();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    // === Undo / Redo ===

    fn push_undo(&mut self) {
        self.undo_stack.push((self.input.clone(), self.cursor_pos));
    }

    fn clear_redo(&mut self) {
        self.redo_stack.clear();
    }

    pub(crate) fn undo(&mut self) {
        if let Some((text, pos)) = self.undo_stack.pop() {
            self.redo_stack.push((self.input.clone(), self.cursor_pos));
            self.input = text;
            self.cursor_pos = pos;
            self.handle_at_trigger();
            self.mark_dirty();
        }
    }

    pub(crate) fn redo(&mut self) {
        if let Some((text, pos)) = self.redo_stack.pop() {
            self.undo_stack.push((self.input.clone(), self.cursor_pos));
            self.input = text;
            self.cursor_pos = pos;
            self.handle_at_trigger();
            self.mark_dirty();
        }
    }

    // === Paste ===

    pub(crate) fn paste(&mut self, text: &str) {
        let clean = text
            .replace("\r\n", "")
            .replace(['\r', '\n'], "")
            .replace('\t', "    ");
        if clean.is_empty() {
            return;
        }
        self.push_undo();
        self.input.insert_str(self.cursor_pos, &clean);
        self.cursor_pos += clean.len();
        self.clear_redo();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    // === Legacy methods ===

    pub(crate) fn push_input(&mut self, c: char) {
        if c == '\t' {
            if self.input.contains('@') || self.at_suggestions.is_some() {
                self.cycle_at_suggestions();
            }
            return;
        }
        self.insert_char(c);
    }

    pub(crate) fn pop_input(&mut self) {
        self.delete_before_cursor();
    }

    pub(crate) fn insert_newline(&mut self) {
        self.push_undo();
        if self.cursor_pos == self.input.len() {
            self.input.push('\n');
        } else {
            self.input.insert(self.cursor_pos, '\n');
        }
        self.cursor_pos += 1;
        self.clear_redo();
        self.mark_dirty();
    }

    pub(crate) fn submit(&mut self) {
        if self.at_suggestions.is_some() {
            self.insert_at_suggestion();
            return;
        }
        if self.input.is_empty() {
            self.input_flash = 3;
            return;
        }
        let content = std::mem::take(&mut self.input).trim().to_string();
        self.cursor_pos = 0;
        self.history_pos = None;
        self.undo_stack.clear();
        self.redo_stack.clear();
        if content.is_empty() {
            return;
        }

        // Handle bash prefix (!)
        if content.starts_with('!') {
            let command = content[1..].trim().to_string();
            if !command.is_empty() {
                self.run_bash_command(&command);
            }
            return;
        }

        self.input_history.push(content.clone());
        if let Some(response) = self.handle_slash(&content) {
            self.add_system_msg(response);
            return;
        }
        if self.turn_active {
            self.message_queue.push(crate::model::QueuedMessage {
                content,
                kind: crate::model::QueuedMessageKind::Steering,
            });
            self.scroll = 0;
            self.mark_dirty();
            return;
        }
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((content, id));
        self.scroll = 0;
        self.messages_changed();
    }

    /// Run a bash command and display output
    fn run_bash_command(&mut self, command: &str) {
        let result = bash::execute_bash(command);
        let output_msg = format!("$ {}\n{}", command, result);
        self.add_system_msg(output_msg);
        self.scroll = 0;
        self.messages_changed();
    }

    // === Input History ===

    pub(crate) fn history_prev(&mut self) {
        if self.input_history.is_empty() {
            self.input_flash = 3;
            return;
        }
        let pos = match self.history_pos {
            Some(p) if p > 0 => p - 1,
            Some(p) => p,
            None => self.input_history.len() - 1,
        };
        self.history_pos = Some(pos);
        self.input = self.input_history[pos].clone();
        self.cursor_pos = self.input.len();
        self.mark_dirty();
    }

    pub(crate) fn history_next(&mut self) {
        let pos = match self.history_pos {
            Some(p) => p + 1,
            None => {
                self.input_flash = 3;
                return;
            }
        };
        if pos >= self.input_history.len() {
            self.history_pos = None;
            self.input.clear();
            self.cursor_pos = 0;
        } else {
            self.history_pos = Some(pos);
            self.input = self.input_history[pos].clone();
            self.cursor_pos = self.input.len();
        }
        self.mark_dirty();
    }

    // === @-ref suggestions ===

    fn handle_at_trigger(&mut self) {
        if self.input.contains('@') {
            let query = self.input.split('@').next_back().unwrap_or("").to_string();
            let needs_refresh = self.last_at_query.as_ref() != Some(&query)
                || self.at_suggestions.is_none();
            if needs_refresh {
                self.last_at_query = Some(query.clone());
                self.refresh_at_suggestions();
            }
        } else {
            self.at_suggestions = None;
            self.at_selected = None;
            self.last_at_query = None;
        }
    }

    fn refresh_at_suggestions(&mut self) {
        let query = self.input.split('@').next_back().unwrap_or("").to_string();
        let mut suggestions = crate::file_refs::complete_at_ref(&self.input, ".", 50);
        if suggestions.len() > 1 && !query.is_empty() {
            let refs: Vec<&str> = suggestions.iter().map(|s| s.as_str()).collect();
            suggestions = crate::fuzzy::fuzzy_filter(&query, &refs, 10)
                .into_iter()
                .map(|s| s.to_string())
                .collect();
        }
        if suggestions.is_empty() {
            suggestions = crate::file_refs::find_files("", ".", 10);
        }
        if suggestions.is_empty() {
            self.at_suggestions = None;
            self.at_selected = None;
            return;
        }
        self.at_suggestions = Some(suggestions);
        self.at_selected = Some(0);
        self.mark_dirty();
    }

    fn cycle_at_suggestions(&mut self) {
        if let Some(suggestions) = self.at_suggestions.as_mut() {
            let idx = self.at_selected.map(|i| (i + 1) % suggestions.len()).unwrap_or(0);
            self.at_selected = Some(idx);
            self.mark_dirty();
        } else {
            self.refresh_at_suggestions();
        }
    }

    fn insert_at_suggestion(&mut self) {
        if let Some(idx) = self.at_selected {
            if let Some(suggestions) = self.at_suggestions.take() {
                if let Some(selected) = suggestions.get(idx) {
                    self.input = crate::file_refs::insert_at_ref(&self.input, selected);
                    self.cursor_pos = self.input.len();
                }
            }
            self.at_selected = None;
            self.last_at_query = None;
            self.mark_dirty();
        }
    }
}

use crate::model::{AppState, ChatMessage, Role};
use crate::Event;

mod agent;
mod bash;
mod input;
mod queue;
mod slash;

pub(crate) fn now() -> f64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs_f64())
        .unwrap_or(0.0)
}

pub(crate) fn strip_tool_markers(content: &str) -> String {
    if let Some(pos) = content.find("TOOL:") {
        let before = &content[..pos];
        return before.trim_end().to_string();
    }
    let mut result = String::new();
    for line in content.lines() {
        let trimmed = line.trim();
        if trimmed.starts_with('{') {
            if let Ok(val) = serde_json::from_str::<serde_json::Value>(trimmed) {
                if val.get("name").is_some() && val.get("arguments").is_some() {
                    continue;
                }
            }
        }
        if !result.is_empty() {
            result.push('\n');
        }
        result.push_str(line);
    }
    result
}

pub(crate) fn content_has_tool_markers(content: &str) -> bool {
    if content.contains("TOOL:") {
        return true;
    }
    content.lines().any(|line| {
        let trimmed = line.trim();
        if !trimmed.starts_with('{') {
            return false;
        }
        serde_json::from_str::<serde_json::Value>(trimmed)
            .map(|v| v.get("name").is_some() && v.get("arguments").is_some())
            .unwrap_or(false)
    })
}

impl AppState {
    pub fn update(&mut self, event: Event) {
        match event {
            Event::Input(c) => self.push_input(c),
            Event::Backspace => self.pop_input(),
            Event::Newline => self.insert_newline(),
            Event::CursorLeft => self.cursor_left(),
            Event::CursorRight => self.cursor_right(),
            Event::CursorStart => self.cursor_start(),
            Event::CursorEnd => self.cursor_end(),
            Event::DeleteWord => self.delete_word(),
            Event::DeleteToEnd => self.delete_to_end(),
            Event::DeleteToStart => self.delete_to_start(),
            Event::KillChar => self.kill_char(),
            Event::HistoryPrev => self.history_prev(),
            Event::HistoryNext => self.history_next(),
            Event::Undo => self.undo(),
            Event::Redo => self.redo(),
            Event::CursorWordLeft => self.cursor_word_left(),
            Event::CursorWordRight => self.cursor_word_right(),
            Event::Paste(text) => self.paste(&text),
            Event::Submit => self.submit(),
            Event::ScrollUp => {
                if self.messages.is_empty() && !self.turn_active {
                    self.input_flash = 3;
                }
                self.scroll = self.scroll.saturating_add(1);
            }
            Event::ScrollDown => {
                if self.scroll == 0 {
                    self.input_flash = 3;
                }
                self.scroll = self.scroll.saturating_sub(1);
            }
            Event::Quit => {}
            Event::Reset => *self = AppState::default(),
            Event::AgentThinking { id } => {
                self.set_thinking(id);
                self.ensure_turn_complete_last();
            }
            Event::AgentThoughtDone { id } => {
                self.add_thought(id);
                self.ensure_turn_complete_last();
            }
            Event::AgentToolStart { id, name } => {
                self.start_tool(id, name);
                self.ensure_turn_complete_last();
            }
            Event::AgentToolEnd { duration_secs, output } => {
                self.end_tool(duration_secs, output);
                self.ensure_turn_complete_last();
            }
            Event::AgentResponse { id, content } => {
                self.append_response(id, content);
                self.ensure_turn_complete_last();
            }
            Event::AgentTurnComplete { id, duration_secs } => {
                self.complete_turn(id, duration_secs);
                self.ensure_turn_complete_last();
            }
            Event::AgentDone { id } => self.finish_turn(id),
            Event::AgentError { id, message } => {
                self.add_error(id, message);
                self.ensure_turn_complete_last();
            }
            Event::SwitchModel { provider, model } => self.switch_model(provider, model),
            Event::FollowUp => self.queue_follow_up(),
            Event::Abort => self.abort_queue(),
            Event::SpawnAgent => {}
            Event::ToggleExpand => self.toggle_expand_all(),
        }
    }

    fn toggle_expand_all(&mut self) {
        self.all_collapsed = !self.all_collapsed;
        self.messages_changed();
    }

    fn switch_model(&mut self, provider: String, model: String) {
        self.current_provider = provider.clone();
        self.current_model = model.clone();
        self.add_system_msg(format!("Switched to {}/{}", provider, model));
    }

    pub fn peek_queue(&self) -> Option<&(String, String)> {
        self.request_queue.front()
    }

    pub fn pop_queue(&mut self) -> Option<(String, String)> {
        self.request_queue.pop_front()
    }

    fn add_system_msg(&mut self, content: String) {
        self.messages.push(ChatMessage {
            role: Role::System,
            content,
            timestamp: now(),
            id: "system".to_string(),
        });
        self.messages_changed();
    }

    /// Move TurnComplete to the end of messages and bump its timestamp.
    /// Called after every agent event to ensure TurnComplete remains last.
    fn ensure_turn_complete_last(&mut self) {
        if let Some(idx) = self.messages.iter().position(|m| m.role == Role::TurnComplete) {
            let mut tc = self.messages.remove(idx);
            tc.timestamp = now();
            self.messages.push(tc);
            self.messages_changed();
        }
    }
}

